-ShenandoahEvacOOMHandler::ShenandoahEvacOOMHandler() :
-  _num_counters(calc_num_counters()) {
-
-  assert(_num_counters > 0, "sanity");
-  assert(is_power_of_2(_num_counters), "must be");
