-uint64_t ShenandoahEvacOOMHandler::hash_pointer(const void* p) {
-  // Bit mixing function from MurmurHash3
-  uint64_t key = (uintptr_t)p;
-  key ^= (key >> 33);
-  key *= UINT64_C(0xff51afd7ed558ccd);
-  key ^= (key >> 33);
-  key *= UINT64_C(0xc4ceb9fe1a85ec53);
-  key ^= (key >> 33);
-  return key;
-}
