+                if (!first)
+                    sb.append(", ");
+                first = false;
+
+                Name name = value.fst.name;
+                if (len > 1 || name != name.table.names.value) {
+                    sb.append(name);
+                    sb.append('=');
+                }
+                sb.append(value.snd);
+            }
+            sb.append(')');
+        }
+        return sb.toString();
+    }
